    productVariants {
      id
      title
      sku
      barcode
      price
      compareAtPrice
      inventoryQuantity
      selectedOptions {
        name
        value
      }
      inventoryItem {
        id
        tracked
        requiresShipping
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

